File: `/Users/charlesvictormahouve/Documents/GitHub/africandatalayer/lib/server/userTrust.ts`

Update `getTrustTier()` to support elite tier. The current function is:
```typescript
export function getTrustTier(score: number): TrustTier {
  if (score >= 80) return "trusted";
  if (score <= 20) return "restricted";
  if (score <= 49) return "new";
  return "standard";
}
```

Change to:
```typescript
export function getTrustTier(score: number): TrustTier {
  if (score >= 90) return "elite";
  if (score >= 80) return "trusted";
  if (score <= 20) return "restricted";
  if (score <= 49) return "new";
  return "standard";
}
```

Note: Using score >= 90 instead of 85 for sync tier because the DB-backed check with totalApproved >= 50 is handled separately.

Add an async variant that checks DB stats:
```typescript
export async function getTrustTierWithStats(userId: string): Promise<TrustTier> {
  const result = await query<{ trust_score: number | null; total_approved: number }>(
    `SELECT
       up.trust_score,
       COALESCE((
         SELECT COUNT(*)::int FROM admin_reviews ar
         JOIN point_events pe ON pe.id = ar.event_id
         WHERE pe.user_id = $1 AND ar.decision = 'approved'
       ), 0) AS total_approved
     FROM user_profiles up
     WHERE up.id = $1
     LIMIT 1`,
    [userId.toLowerCase().trim()],
  );
  const row = result.rows[0];
  if (!row) return "new";
  const score = normalizeTrustScore(row.trust_score);
  if (score >= 85 && row.total_approved >= 50) return "elite";
  return getTrustTier(score);
}
```

**TASK 2: 6G - Trust Score Auto-Update on Admin Review**
File: `/Users/charlesvictormahouve/Documents/GitHub/africandatalayer/lib/server/userTrust.ts`

Add this function:
```typescript
export async function adjustTrustOnReview(input: {
  userId: string;
  decision: "approved" | "rejected" | "flagged";
}): Promise<{ trustScore: number; trustTier: TrustTier }> {
  let delta: number;
  if (input.decision === "approved") {
    // Check consecutive clean submissions
    let consecutiveClean = 0;
    try {
      const recent = await query<{ decision: string }>(
        `SELECT ar.decision
         FROM admin_reviews ar
         JOIN point_events pe ON pe.id = ar.event_id
         WHERE pe.user_id = $1
         ORDER BY ar.reviewed_at DESC
         LIMIT 20`,
        [input.userId.toLowerCase().trim()],
      );
      for (const row of recent.rows) {
        if (row.decision === "approved") consecutiveClean++;
        else break;
      }
    } catch {
      consecutiveClean = 0;
    }
    delta = consecutiveClean > 10 ? 2 : 1;
  } else if (input.decision === "rejected") {
    delta = -15;
  } else {
    delta = -5;
  }

  const result = await updateUserTrust({ userId: input.userId, delta });
  return { trustScore: result.trustScore, trustTier: result.trustTier };
}
```

**TASK 3: 6H - Trust Score Inactivity Decay**
File: `/Users/charlesvictormahouve/Documents/GitHub/africandatalayer/lib/server/userTrust.ts`

Add this function:
```typescript
export async function decayInactiveTrust(): Promise<{ usersDecayed: number }> {
  const inactive = await query<{ id: string }>(
    `SELECT up.id
     FROM user_profiles up
     WHERE up.trust_score > 0
       AND NOT EXISTS (
         SELECT 1 FROM point_events pe
         WHERE pe.user_id = up.id
           AND pe.created_at > NOW() - INTERVAL '30 days'
       )
       AND EXISTS (
         SELECT 1 FROM point_events pe2
         WHERE pe2.user_id = up.id
       )`,
  );

  let decayed = 0;
  for (const row of inactive.rows) {
    await updateUserTrust({ userId: row.id, delta: -1 });
    decayed++;
  }
  return { usersDecayed: decayed };
}
```

**TASK 4: 6A - GPS Validation**
Create NEW file: `/Users/charlesvictormahouve/Documents/GitHub/africandatalayer/lib/server/gpsValidation.ts`

```typescript
import { haversineKm } from "./submissionFraud.js";
import type { GpsIntegrityReport, SubmissionLocation } from "../../shared/types.js";

export interface GpsValidationResult {
  score: number;
  flags: string[];
  mockDetected: boolean;
  exifMismatch: boolean;
}

export function validateGps(input: {
  submissionLocation: SubmissionLocation | null;
  photoLocation: SubmissionLocation | null;
  gpsIntegrity: GpsIntegrityReport | null;
}): GpsValidationResult {
  let score = 100;
  const flags: string[] = [];
  let mockDetected = false;
  let exifMismatch = false;

  const { gpsIntegrity, submissionLocation, photoLocation } = input;

  // Mock location detected
  if (gpsIntegrity?.mockLocationDetected) {
    score -= 50;
    flags.push("mock_location_detected");
    mockDetected = true;
  }

  // GPS accuracy = 0 (impossible value)
  if (gpsIntegrity?.gpsAccuracyMeters === 0) {
    score -= 20;
    flags.push("zero_gps_accuracy");
  } else if (gpsIntegrity?.gpsAccuracyMeters !== null && gpsIntegrity?.gpsAccuracyMeters !== undefined) {
    // Low precision (high accuracy value = less precise)
    if (gpsIntegrity.gpsAccuracyMeters > 100) {
      score -= 10;
      flags.push("low_gps_precision");
    }
  }

  // EXIF GPS vs submission GPS mismatch
  if (submissionLocation && photoLocation) {
    const distance = haversineKm(submissionLocation, photoLocation);
    if (distance > 0.5) {
      score -= 30;
      flags.push("exif_gps_mismatch");
      exifMismatch = true;
    }
  }

  // No integrity report at all
  if (!gpsIntegrity) {
    score -= 15;
    flags.push("no_gps_integrity_report");
  }

  return {
    score: Math.max(0, Math.min(100, score)),
    flags,
    mockDetected,
    exifMismatch,
  };
}
```

**TASK 5: 6F - GPS Anomaly Detection Batch**
Create NEW file: `/Users/charlesvictormahouve/Documents/GitHub/africandatalayer/lib/server/gpsAnomalyDetection.ts`

```typescript
import { query } from "./db.js";

export interface AgentMovementAnalysis {
  userId: string;
  totalSubmissions: number;
  lowPrecisionRate: number;
  uniqueLocationRate: number;
  clusterCount: number;
  flags: string[];
}

export async function analyzeAgentMovementPatterns(
  windowDays = 30,
): Promise<AgentMovementAnalysis[]> {
  const result = await query<{
    user_id: string;
    latitude: number;
    longitude: number;
    gps_accuracy: number | null;
  }>(
    `SELECT
       pe.user_id,
       pe.latitude,
       pe.longitude,
       (pe.details #>> '{gpsIntegrity,gpsAccuracyMeters}')::numeric AS gps_accuracy
     FROM point_events pe
     WHERE pe.created_at > NOW() - make_interval(days => $1::int)
     ORDER BY pe.user_id, pe.created_at`,
    [windowDays],
  );

  const byUser = new Map<string, Array<{ lat: number; lon: number; accuracy: number | null }>>();
  for (const row of result.rows) {
    const entries = byUser.get(row.user_id) ?? [];
    entries.push({
      lat: Number(row.latitude),
      lon: Number(row.longitude),
      accuracy: row.gps_accuracy !== null ? Number(row.gps_accuracy) : null,
    });
    byUser.set(row.user_id, entries);
  }

  const analyses: AgentMovementAnalysis[] = [];

  for (const [userId, points] of byUser) {
    if (points.length < 3) continue;

    const flags: string[] = [];

    // Coordinate precision analysis
    const lowPrecision = points.filter(
      (p) => p.accuracy !== null && p.accuracy > 100,
    ).length;
    const lowPrecisionRate = lowPrecision / points.length;
    if (lowPrecisionRate > 0.8) {
      flags.push("high_low_precision_rate");
    }

    // Location diversity: unique locations within 200m radius
    const uniqueLocations: Array<{ lat: number; lon: number }> = [];
    for (const point of points) {
      const isNearExisting = uniqueLocations.some((existing) => {
        const dlat = point.lat - existing.lat;
        const dlon = point.lon - existing.lon;
        // Rough 200m check (~0.002 degrees)
        return Math.abs(dlat) < 0.002 && Math.abs(dlon) < 0.002;
      });
      if (!isNearExisting) {
        uniqueLocations.push({ lat: point.lat, lon: point.lon });
      }
    }
    const uniqueLocationRate = uniqueLocations.length / points.length;
    if (uniqueLocationRate < 0.3) {
      flags.push("low_location_diversity");
    }

    // Simple cluster detection (DBSCAN-like with 200m radius)
    const clusterRadius = 0.002; // ~200m
    const visited = new Set<number>();
    let clusterCount = 0;
    for (let i = 0; i < points.length; i++) {
      if (visited.has(i)) continue;
      const cluster = [i];
      visited.add(i);
      for (let j = i + 1; j < points.length; j++) {
        if (visited.has(j)) continue;
        const dlat = Math.abs(points[i]!.lat - points[j]!.lat);
        const dlon = Math.abs(points[i]!.lon - points[j]!.lon);
        if (dlat < clusterRadius && dlon < clusterRadius) {
          cluster.push(j);
          visited.add(j);
        }
      }
      if (cluster.length >= 2) clusterCount++;
    }

    analyses.push({
      userId,
      totalSubmissions: points.length,
      lowPrecisionRate: Math.round(lowPrecisionRate * 100) / 100,
      uniqueLocationRate: Math.round(uniqueLocationRate * 100) / 100,
      clusterCount,
      flags,
    });
  }

  return analyses;
}
```

