 59→export function getCronDispatchSchedule(now: Date): CronDispatchSchedule {
 60→  const hour = now.getUTCHours();
 61→  const minute = now.getUTCMinutes();
 62→  const dayOfWeek = now.getUTCDay();
 63→  const dayOfMonth = now.getUTCDate();
 64→  const isDailyCronWindow = hour === 6 && minute === 0;
 65→
 66→  return {
 67→    weeklySnapshot: isDailyCronWindow && dayOfWeek === 1,
 68→    monthlyRollup: isDailyCronWindow && dayOfMonth === 1,
 69→    dailyRoadSnapshot: isDailyCronWindow,
 70→  };
 71→}
