193→export async function GET(request: Request): Promise<Response> {
194→  const url = new URL(request.url);
195→  const view = url.searchParams.get("view") ?? "snapshots";
196→
197→  // Daily cron dispatcher (Hobby-compatible) - authenticated via CRON_SECRET.
198→  if (view === "cron_dispatch") {
199→    return handleAnalyticsCronDispatchRequest(request);
200→  }
201→
202→  // Weekly snapshot cron trigger - authenticated via CRON_SECRET.
203→  if (view === "cron") {
204→    const unauthorizedResponse = requireCronAuthorization(request);
205→    if (unauthorizedResponse) return unauthorizedResponse;
206→    try {
207→      const dateOverride = url.searchParams.get("date") ?? undefined;
208→      const result = await runWeeklySnapshotCron(dateOverride);
209→      return jsonResponse(result);
210→    } catch (error) {
211→      console.error("Snapshot cron failed:", error);
212→      return errorResponse(
213→        error instanceof Error ? error.message : "Snapshot failed",
214→        500,
215→      );
216→    }
217→  }
218→
219→  // Monthly rollup cron trigger - authenticated via CRON_SECRET.
220→  if (view === "cron_monthly") {
221→    const unauthorizedResponse = requireCronAuthorization(request);
222→    if (unauthorizedResponse) return unauthorizedResponse;
223→    try {
224→      const dateOverride = url.searchParams.get("date") ?? undefined;
225→      const result = await runMonthlyRollupCron(dateOverride);
226→      return jsonResponse(result);
227→    } catch (error) {
228→      console.error("Monthly rollup cron failed:", error);
229→      return errorResponse(
230→        error instanceof Error ? error.message : "Monthly rollup failed",
231→        500,
232→      );
233→    }
234→  }
235→
236→  // Daily transport-road summary cron trigger - authenticated via CRON_SECRET.
237→  if (view === "cron_daily_road") {
238→    const unauthorizedResponse = requireCronAuthorization(request);
239→    if (unauthorizedResponse) return unauthorizedResponse;
240→    try {
241→      const dateOverride = url.searchParams.get("date") ?? undefined;
242→      const result = await runDailyRoadSnapshotCron(dateOverride);
243→      return jsonResponse(result);
244→    } catch (error) {
245→      console.error("Daily road snapshot cron failed:", error);
246→      return errorResponse(
247→        error instanceof Error ? error.message : "Daily road snapshot failed",
248→        500,
249→      );
250→    }
251→  }
252→
253→  // All other views require authenticated user
254→  const user = await requireUser(request);
255→  if (!user) return errorResponse("Unauthorized", 401);
256→
257→  switch (view) {
258→    case "snapshots":
259→      return handleSnapshots(url);
260→    case "deltas":
261→      return handleDeltas(url);
262→    case "monthly":
263→      return handleMonthly(url);
264→    case "trends":
265→      return handleTrends(url);
266→    case "anomalies":
267→      return handleAnomalies();
268→    case "kpi_summary":
269→      return handleKpiSummary();
270→    case "kpi_weekly":
271→      return handleKpiWeekly(url);
272→    default:
273→      return errorResponse(
274→        `Invalid view: ${view}. Valid: snapshots, deltas, monthly, trends, anomalies, kpi_summary, kpi_weekly, cron_dispatch, cron, cron_monthly, cron_daily_road`,
275→        400,
276→      );
277→  }
278→}
