430→async function handleKpiSummary(): Promise<Response> {
431→  const [
432→    wacResult,
433→    verificationResult,
434→    freshnessResult,
435→    fraudResult,
436→    reviewResult,
437→    enrichmentResult,
438→  ] = await Promise.all([
439→    query<{ wac: number }>(
440→      `SELECT COUNT(DISTINCT user_id)::int AS wac
441→       FROM point_events
442→       WHERE created_at >= NOW() - INTERVAL '7 days'`,
443→    ),
444→    query<{ total_points: number; verified_points: number; verification_rate_pct: number }>(
445→      `WITH point_users AS (
446→         SELECT point_id, COUNT(DISTINCT user_id) AS distinct_users
447→         FROM point_events
448→         GROUP BY point_id
449→       )
450→       SELECT
451→         COUNT(*)::int AS total_points,
452→         COUNT(*) FILTER (WHERE distinct_users >= 2)::int AS verified_points,
453→         ROUND(
454→           100.0 * COUNT(*) FILTER (WHERE distinct_users >= 2) / GREATEST(COUNT(*), 1),
455→           1
456→         ) AS verification_rate_pct
457→       FROM point_users`,
458→    ),
459→    query<{ median_age_days: number; avg_age_days: number }>(
460→      `WITH latest_per_point AS (
461→         SELECT point_id, MAX(created_at) AS last_event_at
462→         FROM point_events
463→         GROUP BY point_id
464→       ),
465→       ages AS (
466→         SELECT EXTRACT(EPOCH FROM (NOW() - last_event_at)) / 86400.0 AS age_days
467→         FROM latest_per_point
468→       )
469→       SELECT
470→         ROUND(PERCENTILE_CONT(0.5) WITHIN GROUP (ORDER BY age_days)::numeric, 1) AS median_age_days,
471→         ROUND(AVG(age_days)::numeric, 1) AS avg_age_days
472→       FROM ages`,
473→    ),
474→    query<{ events_with_fraud_check: number; mismatch_events: number; fraud_rate_pct: number }>(
475→      `SELECT
476→         COUNT(*) FILTER (
477→           WHERE details #>> '{fraudCheck,primaryPhoto,submissionGpsMatch}' IS NOT NULL
478→         )::int AS events_with_fraud_check,
479→         COUNT(*) FILTER (
480→           WHERE details #>> '{fraudCheck,primaryPhoto,submissionGpsMatch}' = 'false'
481→         )::int AS mismatch_events,
482→         ROUND(
483→           100.0 * COUNT(*) FILTER (
484→             WHERE details #>> '{fraudCheck,primaryPhoto,submissionGpsMatch}' = 'false'
485→           ) / GREATEST(
486→             COUNT(*) FILTER (
487→               WHERE details #>> '{fraudCheck,primaryPhoto,submissionGpsMatch}' IS NOT NULL
488→             ),
489→             1
490→           ),
491→           1
492→         ) AS fraud_rate_pct
493→       FROM point_events
494→       WHERE created_at >= NOW() - INTERVAL '30 days'`,
495→    ),
496→    query<{ pending_review: number; high_risk_events: number }>(
497→      `SELECT
498→         COUNT(*) FILTER (WHERE COALESCE(details->>'reviewStatus', 'auto_approved') = 'pending_review')::int AS pending_review,
499→         COUNT(*) FILTER (
500→           WHERE (details->>'riskScore') ~ '^-?\\d+(\\.\\d+)?$'
501→             AND (details->>'riskScore')::numeric >= 60
502→         )::int AS high_risk_events
503→       FROM point_events`,
504→    ),
505→    query<{ enrichment_rate_pct: number }>(
506→      `WITH point_summary AS (
507→         SELECT
508→           point_id,
509→           BOOL_OR(event_type = 'CREATE_EVENT') AS has_create,
510→           BOOL_OR(event_type = 'ENRICH_EVENT') AS has_enrich
511→         FROM point_events
512→         GROUP BY point_id
513→       )
514→       SELECT ROUND(
515→         100.0 * COUNT(*) FILTER (WHERE has_enrich) / GREATEST(COUNT(*), 1),
516→         1
517→       ) AS enrichment_rate_pct
518→       FROM point_summary
519→       WHERE has_create`,
520→    ),
521→  ]);
522→
